  ('dietitian-moex-02116', 'dietitian', 'dietitian-moex-107-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列有關重症病人的營養處置，那些正確？①血清白蛋白、運鐵蛋白及前白蛋白（serum albumin, transferrin,', '["入住加護病房24～48小時內儘早灌食（early feeding）， 接下來的48～72小時內進展至目標熱量", "非肥胖者之熱量估算為25～30大卡／公斤體重（乾體重或 通常體重）", "血液動力學不穩定時要暫停腸道營養，改給靜脈營養  ⑤在加護病房第 1 週內若能攝取 到50～65%目標熱量，就足以達到腸道營養的臨床效益", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "9933f6e8fb40", "answer_pdf_sha1": "99cb4d1e1abb", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02117', 'dietitian', 'dietitian-moex-107-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列何者對於促進手術後復原（enhance recovery after surgery）較有益處？', '["手術前長期禁食", "手術前勿給予預防性抗生素（Antibiotic prophylaxis）", "手術後避免過量給予水分及鹽分", "維持鼻胃管餵食"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "9933f6e8fb40", "answer_pdf_sha1": "99cb4d1e1abb", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02118', 'dietitian', 'dietitian-moex-107-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '一般而言對於嚴重創傷患者的營養需求，下列敘述何者正確？', '["熱量建議量為25～30大卡／公斤體重／天", "熱量建議量為35～45大卡／公斤體重／天", "蛋白質建議量為2.5～3.0公克／公斤體重／天", "PN時醣類至少須達9毫克／公斤體重／分鐘"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "9933f6e8fb40", "answer_pdf_sha1": "99cb4d1e1abb", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02119', 'dietitian', 'dietitian-moex-107-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '王先生在接受Hematopoietic cell transplantation（HCT）之後，發生嚴重的Graft-versus-Host Diseas（e GVHD） 導致之急性腸胃道排斥現象，需使用類固醇和免疫抑制劑來治療，依照五個階段的症狀會有不同的飲食 限制，下列敘述何者錯誤？', '["第一階段因為嚴重的腹瀉，無法進展腸道營養，需從靜脈營養給予補充", "第二階段需讓腸道休息和黏膜修復，只能給予清流質飲食", "第三階段可以逐漸進展到給予固體食物，需注意低渣和低油", "第四階段可以逐漸放寬飲食限制到第五階段恢復原來的飲食型態"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "9933f6e8fb40", "answer_pdf_sha1": "99cb4d1e1abb", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02120', 'dietitian', 'dietitian-moex-107-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '關於慢性肺部阻塞疾病（COPD）的敘述，下列何者正確？', '["可能進展成肺因性心臟病（cor pulmonale）", "很少是由於慢性支氣管炎所造成", "與肺氣腫無關", "肥胖病人不常見"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "9933f6e8fb40", "answer_pdf_sha1": "99cb4d1e1abb", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
